from __future__ import annotations

import logging
import ssl

import socksio

from .._backends.auto import AutoBackend
from .._backends.base import AsyncNetworkBackend, AsyncNetworkStream
from .._exceptions import ConnectionNotAvailable, ProxyError
from .._models import URL, Origin, Request, Response, enforce_bytes, enforce_url
from .._ssl import default_ssl_context
from .._synchronization import AsyncLock
from .._trace import Trace
from .connection_pool import AsyncConnectionPool
from .http11 import AsyncHTTP11Connection
from .interfaces import AsyncConnectionInterface

logger = logging.getLogger("httpcore.socks")


AUTH_METHODS = {
    b"\x00": "NO AUTHENTICATION REQUIRED",
    b"\x01": "GSSAPI",
    b"\x02": "USERNAME/PASSWORD",
    b"\xff": "NO ACCEPTABLE METHODS",
}

REPLY_CODES = {
    b"\x00": "Succeeded",
    b"\x01": "General SOCKS server failure",
    b"\x02": "Connection not allowed by ruleset",
    b"\x03": "Network unreachable",
    b"\x04": "Host unreachable",
    b"\x05": "Connection refused",
    b"\x06": "TTL expired",
    b"\x07": "Command not supported",
    b"\x08": "Address type not supported",
}


async def _init_socks5_connection(
    stream: AsyncNetworkStream,
    *,
    host: bytes,
    port: int,
    auth: tuple[bytes, bytes] | None = None,
) -> None:
    conn = socksio.socks5.SOCKS5Connection()

    # Auth method request
    auth_method = (
        socksio.socks5.SOCKS5AuthMethod.NO_AUTH_REQUIRED
        if auth is None
        else socksio.socks5.SOCKS5AuthMethod.USERNAME_PASSWORD
    )
    conn.send(socksio.socks5.SOCKS5AuthMethodsRequest([auth_method]))
    outgoing_bytes = conn.data_to_send()
    await stream.write(outgoing_bytes)

    # Auth method response
    incoming_bytes = await stream.read(max_bytes=4096)
    response = conn.receive_data(incoming_bytes)
    assert isinstance(response, socksio.socks5.SOCKS5AuthReply)
    if response.method != auth_method:
        requested = AUTH_METHODS.get(auth_method, "UNKNOWN")
        responded = AUTH_METHODS.get(response.method, "UNKNOWN")
        raise ProxyError(
            f"Requested {requested} from proxy server, but got {responded}."
        )

    if response.method == socksio.socks5.SOCKS5AuthMethod.USERNAME_PASSWORD:
        # Username/password request
        assert auth is not None
        username, password = auth
        conn.send(socksio.socks5.SOCKS5UsernamePasswordRequest(username, password))
        outgoing_bytes = conn.data_to_send()
        await stream.write(outgoing_bytes)

        # Username/password response
        incoming_bytes = await stream.read(max_bytes=4096)
        response = conn.receive_data(incoming_bytes)
        assert isinstance(response, socksio.socks5.SOCKS5UsernamePasswordReply)
        if not response.success:
            raise ProxyError("Invalid username/password")

    # Connect request
    conn.send(
        socksio.socks5.SOCKS5CommandRequest.from_address(
            socksio.socks5.SOCKS5Command.CONNECT, (host, port)
        )
    )
    outgoing_bytes = conn.data_to_send()
    await stream.write(outgoing_bytes)

    # Connect response
    incoming_bytes = await stream.read(max_bytes=4096)
    response = conn.receive_data(incoming_bytes)
    assert isinstance(response, socksio.socks5.SOCKS5Reply)
    if response.reply_code != socksio.socks5.SOCKS5ReplyCode.SUCCEEDED:
        reply_code = REPLY_CODES.get(response.reply_code, "UNKOWN")
        raise ProxyError(f"Proxy Server could not connect: {reply_code}.")


class AsyncSOCKSProxy(AsyncConnectionPool):  # pragma: nocover
    """
    A connection pool that sends requests via a SOCKS proxy.
    """

    def __init__(
        self,
        proxy_url: URL | bytes | str,
        proxy_auth: tuple[bytes | str, bytes | str] | None = None,
        ssl_context: ssl.SSLContext | None = None,
        max_connections: int | None = 10,
        max_keepalive_connections: int | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
    ):
        """
        Initialize a connection pool that will communicate via a SOCKS proxy.

        This sets up the proxy URL and authentication (if provided), and stores
        configuration like maximum connections and keepalive behavior.

        Parameters are:
        - proxy_url: The URL to the proxy (str | bytes | URL).
        - proxy_auth: Optional (username, password) tuple for proxy auth.
        - ssl_context: Optional SSLContext to use for TLS (not typically used for SOCKS).
        - max_connections: Maximum total connections for the pool.
        - max_keepalive_connections: Maximum idle connections to keep.
        - keepalive_expiry: Seconds before an idle connection expires.
        - http1: Whether to use HTTP/1.1 connections for the proxied connection.
        """
        super().__init__(
            max_connections=max_connections,
            max_keepalive_connections=max_keepalive_connections,
            keepalive_expiry=keepalive_expiry,
        )

        self.proxy_url = enforce_url(proxy_url)
        # Use proxy URL credentials unless explicit proxy_auth provided.
        if proxy_auth is None and self.proxy_url.user is not None:
            # URL.user / URL.password may be str; convert to bytes
            user = self.proxy_url.user
            password = self.proxy_url.password or ""
            proxy_auth = (user.encode("utf-8"), password.encode("utf-8"))
        elif proxy_auth is not None:
            # Ensure bytes
            proxy_auth = tuple(
                p.encode("utf-8") if isinstance(p, str) else p for p in proxy_auth
            )

        self.proxy_auth = proxy_auth
        self.ssl_context = ssl_context or default_ssl_context()
        self._http1 = http1

        # Internal lock to protect connection creation in concurrent contexts.
        self._create_lock = AsyncLock()

    async def create_connection(
        self,
        origin: Origin,
        trace: Trace | None = None,
        timeout: float | None = None,
    ) -> AsyncConnectionInterface:
        """
        Create a new connection to the configured SOCKS proxy and establish
        a SOCKS handshake to the target origin.

        The returned object implements AsyncConnectionInterface and wraps the
        underlying network stream.

        Parameters:
        - origin: The target origin (host/port/scheme) we want to reach via the proxy.
        - trace: Optional trace object for instrumentation.
        - timeout: Optional timeout in seconds for connection establishment.

        Returns:
        - An AsyncConnectionInterface instance representing the proxied connection.
        """
        # Basic defensive conversion / extraction
        proxy_host = self.proxy_url.host
        proxy_port = self.proxy_url.port or (1080)
        # Convert to bytes for socks library:
        try:
            host_bytes = enforce_bytes(origin.host)
        except Exception:
            host_bytes = enforce_bytes(str(origin.host))

        # For the purposes of this implementation we will open a network stream to
        # the proxy host and perform the SOCKS5 handshake to the desired origin.
        backend = AutoBackend.get_backend(AsyncNetworkBackend)
        stream = await backend.open_network_stream(proxy_host, proxy_port, ssl_context=None)

        # Perform SOCKS5 handshake. We only support SOCKS5 here.
        await _init_socks5_connection(
            stream,
            host=host_bytes,
            port=origin.port,
            auth=self.proxy_auth,
        )

        # Wrap the stream in an HTTP/1.1 connection object if requested,
        # otherwise return a minimal connection wrapper.
        if self._http1:
            connection = AsyncHTTP11Connection(stream, origin=origin)
            return connection
        else:
            # Minimal wrapper implementing the required interface.
            return _SocksProxyConnection(stream, origin, proxy_host, proxy_port)


class _SocksProxyConnection(AsyncConnectionInterface):
    def __init__(
        self,
        stream: AsyncNetworkStream,
        origin: Origin,
        proxy_host: str | bytes,
        proxy_port: int,
    ):
        """
        Lightweight connection wrapper for a proxied connection.

        Parameters:
        - stream: Underlying AsyncNetworkStream already connected and handshaked.
        - origin: The target origin for which this connection was established.
        - proxy_host: The proxy host used for the connection.
        - proxy_port: The proxy port used for the connection.
        """
        self._stream = stream
        self._origin = origin
        self._proxy_host = proxy_host
        self._proxy_port = proxy_port
        self._in_use = False
        self._closed = False

    def can_handle_request(self, request: Request) -> bool:
        """
        Determine whether this connection can be used to handle the given request.

        For SOCKS proxied connections created to reach a specific origin, this
        will return True if the request's URL origin matches the connection's origin.
        """
        try:
            return enforce_url(request.url).origin == self._origin
        except Exception:
            # If the request does not have a URL or origin, conservatively return False.
            return False

    def is_available(self) -> bool:
        """
        Return True if the connection is currently available for use.

        A connection is considered available if it is not currently in use and not closed.
        """
        return (not self._in_use) and (not self._closed)

    def has_expired(self, now: float) -> bool:
        """
        Return True if the connection has expired based on the provided timestamp.

        For this lightweight wrapper we don't implement time-based expiry, so always return False.
        """
        return False

    def is_idle(self) -> bool:
        """
        Return True if the connection is idle (not in use).

        This is used by the connection pool to determine whether the connection
        can be reused or should be closed.
        """
        return not self._in_use

    def is_closed(self) -> bool:
        """
        Return True if the underlying connection has been closed.
        """
        return self._closed

    def info(self) -> dict:
        """
        Return a mapping of informational details about the connection.

        This can include proxy host/port and the target origin.
        """
        return {
            "proxy_host": self._proxy_host,
            "proxy_port": self._proxy_port,
            "origin": str(self._origin),
            "in_use": self._in_use,
            "closed": self._closed,
        }

    def __repr__(self) -> str:
        """
        Return a human-readable representation of this connection for debugging.
        """
        return (
            f"<_SocksProxyConnection proxy={self._proxy_host}:{self._proxy_port} "
            f"origin={self._origin!r} in_use={self._in_use} closed={self._closed}>"
        )